import { apiClient } from './api';

/**
 * 可视化分析服务
 */
export default {
  /**
   * 获取关键词云数据
   * @param {number} novelId 小说ID
   * @returns {Promise<Object>} 关键词云数据
   */
  getKeywordCloud(novelId) {
    if (!novelId || isNaN(parseInt(novelId)) || parseInt(novelId) <= 0) {
      return Promise.reject(new Error('无效的小说ID'));
    }
    return apiClient.get(`/novels/visualization/${novelId}/keywords`);
  },

  /**
   * 获取情感波动数据
   * @param {number} novelId 小说ID
   * @returns {Promise<Object>} 情感波动数据
   */
  getEmotionalFluctuation(novelId) {
    if (!novelId || isNaN(parseInt(novelId)) || parseInt(novelId) <= 0) {
      return Promise.reject(new Error('无效的小说ID'));
    }
    return apiClient.get(`/novels/visualization/${novelId}/emotions`);
  },

  /**
   * 获取结构分析数据
   * @param {number} novelId 小说ID
   * @returns {Promise<Object>} 结构分析数据
   */
  getStructureAnalysis(novelId) {
    if (!novelId || isNaN(parseInt(novelId)) || parseInt(novelId) <= 0) {
      return Promise.reject(new Error('无效的小说ID'));
    }
    return apiClient.get(`/novels/visualization/${novelId}/structure`);
  },

  /**
   * 获取人物关系数据
   * @param {number} novelId 小说ID
   * @returns {Promise<Object>} 人物关系数据
   */
  getCharacterRelationship(novelId) {
    if (!novelId || isNaN(parseInt(novelId)) || parseInt(novelId) <= 0) {
      return Promise.reject(new Error('无效的小说ID'));
    }
    return apiClient.get(`/novels/visualization/${novelId}/characters`);
  },

  /**
   * 获取场景分布数据
   * @param {number} novelId 小说ID
   * @returns {Promise<Object>} 场景分布数据
   */
  getSceneDistribution(novelId) {
    if (!novelId || isNaN(parseInt(novelId)) || parseInt(novelId) <= 0) {
      return Promise.reject(new Error('无效的小说ID'));
    }
    return apiClient.get(`/novels/visualization/${novelId}/scenes`);
  },

  /**
   * 获取小说统计数据
   * @param {number} novelId 小说ID
   * @returns {Promise<Object>} 小说统计数据
   */
  getNovelStatistics(novelId) {
    if (!novelId || isNaN(parseInt(novelId)) || parseInt(novelId) <= 0) {
      return Promise.reject(new Error('无效的小说ID'));
    }
    return apiClient.get(`/novels/visualization/${novelId}/statistics`);
  },

  /**
   * 获取所有可视化数据
   * @param {number} novelId 小说ID
   * @returns {Promise<Object>} 所有可视化数据
   */
  getAllVisualizationData(novelId) {
    if (!novelId || isNaN(parseInt(novelId)) || parseInt(novelId) <= 0) {
      return Promise.reject(new Error('无效的小说ID'));
    }
    return apiClient.get(`/novels/visualization/${novelId}/all`);
  }
};
